import { createSlice } from "@reduxjs/toolkit";

import { uiActions } from "./ui-slice";

const firebase = "https://redux-f63a6-default-rtdb.firebaseio.com/cart.json";

const initialState = {
  items: [],
  totalQuantity: 0,
};

const cartSlice = createSlice({
  name: "cart",
  initialState: initialState,
  reducers: {
    addItemToCart: (state, action) => {
      const item = action.payload;
      const existingItem = state.items.find(
        (cartItem) => cartItem.id === item.id,
      );
      state.totalQuantity++;
      if (!existingItem) {
        state.items.push({
          id: item.id,
          quantity: 1,
          price: item.price,
          total: item.price,
          name: item.title,
        });
      } else {
        existingItem.quantity++;
        existingItem.total = existingItem.total + item.price;
      }
    },
    removeItemFromCart: (state, action) => {
      const id = action.payload;
      const existingItem = state.items.find((item) => item.id === id);
      state.totalQuantity--;
      if (existingItem.quantity === 1) {
        state.items = state.items.filter((cartItem) => cartItem.id !== id);
      } else {
        existingItem.quantity--;
      }
    },
  },
});

const sendCartData = (cart) => {
  return async (dispatch) => {
    dispatch(
      uiActions.setNotification({
        status: "pending",
        title: "Sending",
        message: "Fetching cart data!",
      }),
    );
    try {
      const sendResponse = async 
      const response = await fetch(
        "https://redux-f63a6-default-rtdb.firebaseio.com/cart.json",
        {
          method: "PUT",
          body: JSON.stringify(cart),
        },
      );
      if (!response.ok) {
        throw new Error("Sending data to the database failed!");
      }

      dispatch(
        uiActions.setNotification({
          status: "success",
          title: "Success!",
          message: "Sent cart data successfully!",
        }),
      );
    } catch (error) {
      dispatch(
        uiActions.setNotification({
          status: "rejected",
          title: "Error!",
          message: error.message,
        }),
      );
    }
  };
};

export const cartActions = cartSlice.actions;

export default cartSlice;
